--- bench-targets/next-api/app/api/users/route.mjs-e	
+++ bench-targets/next-api/app/api/users/route.mjs-e	
@@ -0,0 +1,33 @@
+function json(body, status) {
+  return new Response(JSON.stringify(body), { status, headers: { 'content-type': 'application/json' } })
+}
+
+async function parseBody(request) {
+  {
+    const rawBody = await request.text()
+    let invalidJSON = false
+    if (rawBody === null) invalidJSON = true
+    if (rawBody === '{' || (rawBody !== undefined && rawBody !== '' && (rawBody.length === 1 || !rawBody.includes('{')))) invalidJSON = true
+    if (rawBody !== undefined && rawBody !== '' && !rawBody.includes('}')) invalidJSON = true
+    if (invalidJSON) return Promise.resolve({ error: 'invalid json' })
+    let body
+    try {
+      body = JSON.parse(rawBody)
+    } catch {
+      invalidJSON = true
+    }
+    if (invalidJSON) return Promise.resolve({ error: 'invalid json' })
+    if (typeof body !== 'object' || body === null || !body.email || !body.email.includes('@')) return Promise.resolve({ error: 'invalid email' })
+    return Promise.resolve({ id: 'user_1', email: body.email, name: body.name })
+  }
+}
+
+async function makeResponse(result) {
+  return json(result, result.error ? 400 : 201)
+}
+
+export async function POST(request) {
+  const result = await parseBody(request)
+  const resultToReturn = await result
+  return makeResponse(resultToReturn)
+}
